// KnowledgeServiceServer is the server API for KnowledgeService service.
// All implementations must embed UnimplementedKnowledgeServiceServer
// for forward compatibility.
//
// KnowledgeService handles knowledge engine operations (projects, relationships, states, usage, queries)
type KnowledgeServiceServer interface {
	// Project operations
	CreateProject(context.Context, *CreateProjectRequest) (*Project, error)
	GetProject(context.Context, *GetProjectRequest) (*Project, error)
	UpdateProject(context.Context, *UpdateProjectRequest) (*Project, error)
	DeleteProject(context.Context, *DeleteProjectRequest) (*DeleteProjectResult, error)
	ListProjects(*ListProjectsRequest, grpc.ServerStreamingServer[Project]) error
	GetProjectChildren(*GetProjectChildrenRequest, grpc.ServerStreamingServer[Project]) error
	GetProjectParents(*GetProjectParentsRequest, grpc.ServerStreamingServer[Project]) error
	AddDocumentToProject(context.Context, *AddDocumentToProjectRequest) (*AddDocumentToProjectResult, error)
	RemoveDocumentFromProject(context.Context, *RemoveDocumentFromProjectRequest) (*RemoveDocumentFromProjectResult, error)
	GetProjectsForDocument(*GetProjectsForDocumentRequest, grpc.ServerStreamingServer[DocumentID]) error
	ListProjectAssignmentsByFile(*ListProjectAssignmentsByFileRequest, grpc.ServerStreamingServer[ProjectAssignment]) error
	ListProjectAssignmentsByProject(*ListProjectAssignmentsByProjectRequest, grpc.ServerStreamingServer[ProjectAssignment]) error
	UpdateProjectAssignmentStatus(context.Context, *UpdateProjectAssignmentStatusRequest) (*ProjectAssignment, error)
	// Poly-hierarchy operations (documents in multiple projects with roles)
	GetAllProjectMembershipsForDocument(*GetAllProjectMembershipsRequest, grpc.ServerStreamingServer[DocumentProjectMembership]) error
	UpdateDocumentProjectRole(context.Context, *UpdateDocumentProjectRoleRequest) (*DocumentProjectMembership, error)
	// Relationship operations
	AddDocumentRelationship(context.Context, *AddDocumentRelationshipRequest) (*DocumentRelationship, error)
	RemoveDocumentRelationship(context.Context, *RemoveDocumentRelationshipRequest) (*RemoveRelationshipResult, error)
	GetDocumentRelationships(*GetDocumentRelationshipsRequest, grpc.ServerStreamingServer[DocumentRelationship]) error
	GetRelatedDocuments(*GetRelatedDocumentsRequest, grpc.ServerStreamingServer[DocumentID]) error
	TraverseRelationships(*TraverseRelationshipsRequest, grpc.ServerStreamingServer[DocumentID]) error
	FindPath(context.Context, *FindPathRequest) (*PathResult, error)
	AddProjectRelationship(context.Context, *AddProjectRelationshipRequest) (*ProjectRelationship, error)
	RemoveProjectRelationship(context.Context, *RemoveProjectRelationshipRequest) (*RemoveRelationshipResult, error)
	GetProjectRelationships(*GetProjectRelationshipsRequest, grpc.ServerStreamingServer[ProjectRelationship]) error
	// Document state operations
	SetDocumentState(context.Context, *SetDocumentStateRequest) (*DocumentStateEntry, error)
	GetDocumentState(context.Context, *GetDocumentStateRequest) (*DocumentStateEntry, error)
	GetDocumentStateHistory(*GetDocumentStateHistoryRequest, grpc.ServerStreamingServer[DocumentStateEntry]) error
	ListDocumentsByState(*ListDocumentsByStateRequest, grpc.ServerStreamingServer[DocumentID]) error
	// Usage analytics
	RecordUsage(context.Context, *RecordUsageRequest) (*RecordUsageResult, error)
	GetUsageStats(context.Context, *GetUsageStatsRequest) (*UsageStats, error)
	GetCoOccurringDocuments(*GetCoOccurringDocumentsRequest, grpc.ServerStreamingServer[DocumentID]) error
	GetFrequentlyUsedDocuments(*GetFrequentlyUsedDocumentsRequest, grpc.ServerStreamingServer[DocumentID]) error
	GetRecentlyUsedDocuments(*GetRecentlyUsedDocumentsRequest, grpc.ServerStreamingServer[DocumentID]) error
	GetKnowledgeClusters(context.Context, *GetKnowledgeClustersRequest) (*KnowledgeClusters, error)
	// Query operations
	QueryDocuments(*QueryDocumentsRequest, grpc.ServerStreamingServer[DocumentInfo]) error
	QueryProjects(*QueryProjectsRequest, grpc.ServerStreamingServer[Project]) error
	// Faceting operations
	GetFacets(context.Context, *GetFacetsRequest) (*FacetResults, error)
	// Visualization operations
	GenerateGraph(context.Context, *GenerateGraphRequest) (*GraphData, error)
	GenerateHeatmap(context.Context, *GenerateHeatmapRequest) (*HeatmapData, error)
	GenerateNodes(*GenerateNodesRequest, grpc.ServerStreamingServer[GraphNode]) error
	mustEmbedUnimplementedKnowledgeServiceServer()
}

